import { InternalTreeMapNode } from '../internal.js';
export type LeafNode = Omit<InternalTreeMapNode, 'children'>;
export type ClusterNode = Omit<InternalTreeMapNode, 'children'> & {
    children: InternalTreeMapNode[];
};
export type RootNode = ClusterNode;
export declare const isLeaf: (node: LeafNode | ClusterNode | RootNode) => node is LeafNode;
export declare const isCluster: (node: LeafNode | ClusterNode | RootNode) => node is ClusterNode;
